import csv
import os

from bytewax import operators as op
from bytewax.connectors.stdio import StdOutSink
from bytewax.dataflow import Dataflow
from bytewax.operators import StatefulLogic

OUTPUT_FILE = "output.csv"


class MovingAverageLogic(StatefulLogic):
    """Stateful logic to compute the moving average of the last N readings."""

    def __init__(self, window_size: int = 3):
        self.window_size = window_size

    def on_notify(self, notification):
        return self.snapshot()

    def on_snapshot(self):
        return tuple(self.state) if self.state else ()

    def on_restore(self, snapshot):
        self.state = list(snapshot) if snapshot else []

    def on_build(self):
        self.state = []

    def on_push(self, value):
        temp = value
        self.state.append(temp)
        if len(self.state) > self.window_size:
            self.state = self.state[-self.window_size :]
        avg = sum(self.state) / len(self.state)
        # Return a new state tuple (immutable) and the rounded result
        return (tuple(self.state), round(avg, 2))


flow = Dataflow("sensor_moving_average")


def _csv_input():
    """Read lines from input.csv, yielding one line at a time."""
    with open("input.csv", "r") as f:
        for line in f:
            line = line.strip()
            if line:
                yield line


def _parse_line(line: str) -> tuple:
    """Parse a CSV line into (sensor_id, temperature)."""
    sensor_id, temp_str = line.split(",")
    return (sensor_id, float(temp_str))


def _format_output(item):
    """Format (sensor_id, moving_average) as 'sensor_id,moving_average'."""
    sensor_id, avg = item
    return f"{sensor_id},{avg:.2f}"


# Remove any existing output file to start fresh
if os.path.exists(OUTPUT_FILE):
    os.remove(OUTPUT_FILE)


def _csv_output_handler(line: str):
    """Append a formatted line to output.csv."""
    with open(OUTPUT_FILE, "a") as f:
        f.write(line + "\n")


# Build the dataflow
stream = op.input("input", flow, _csv_input)
parsed = op.map("parse", stream, _parse_line)
with_state = op.stateful_map(
    "moving_average",
    parsed,
    lambda key: MovingAverageLogic(window_size=3),
)
formatted = op.map("format", with_state, _format_output)
op.output("output", formatted, _csv_output_handler)

